  ('heelevel3-6f0ba476-moex-00422', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設獨占廠商的邊際成本固定且沒有差別取價，當政府對獨占市場中的財貨課稅時，在獲得相同 稅後產出的假設下，從價稅與從量稅兩者經濟效果之比較，何者正確？', '["從價稅稅收等於從量稅稅收", "從價稅稅收大於從量稅稅收", "從價稅稅收小於從量稅稅收", "從價稅稅收無法與從量稅稅收比較"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00423', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '若對一完全競爭市場課徵商品稅，關於超額負擔之敘述，下列何者正確？', '["若超額負擔等於零，則所得分配符合水平的公平", "若超額負擔等於零，則所得分配符合垂直的公平", "若生產者的邊際成本曲線為水平，則該市場的生產者沒有超額負擔", "若生產者的邊際成本曲線為垂直，則僅該市場的消費者有超額負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00424', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設x商品為完全競爭市場，受補償需求曲線為P=100-2Q，MC=6。現政府對此商品提供每單 位2元的補貼，此補貼政策造成的超額負擔為多少元？', '["1", "2", "48", "96"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00425', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '一消費者消費x和y兩財貨，他只有勞動所得。若政府對x和y以及休閒都課以稅率25%的從價 稅，下列敘述何者錯誤？', '["此一課稅方式等同定額稅", "此一課稅方式等同對他的時間稟賦（timeendowment）價值課徵25%的稅率", "此一課稅方式沒有無謂的損失", "此一課稅方式可以達到最佳（firstbest）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00426', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設家庭效用水準決定於家庭總消費、先生的勞動時數與太太的勞動時數，並隨家庭總消費的增 加而增加，夫妻任一方工作時數的增加而減少。假設只有勞動所得，夫與妻的工作時數彼此無關 且只和自己的工資率有關。若先生的勞動供給彈性較太太的勞動供給彈性低，為使課稅引起的超 額負擔最小，租稅的設計應該：', '["對家庭總所得課徵", "對先生的勞動所得課較高的邊際稅率", "對太太的勞動所得課較高的邊際稅率", "對夫妻的勞動所得課較相同的邊際稅率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00427', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '下列何種課稅方法會產生逃稅？', '["依據建築物窗子的大小課稅", "對鬍子長度課稅", "根據交易憑證課徵所得稅", "某一國家提高所得稅因此造成百姓移民到其他國家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00428', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '勞動市場為完全競爭，供給曲線為W=100L，需求曲線為W=1,000，其中W為工資率，L為每 天工作時數。若政府決定對工資所得課稅20%，課稅後每天的工作時數是多少？', '["24", "14", "10", "8"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00429', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '在兩期（第1期與第2期）消費的模型中，且兩期消費皆為正常財，若實施利息支出可做為費用 扣除的所得稅制度，會使借款者的第1期消費如何變動？', '["減少", "增加", "不變", "無法判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00430', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設在一開放的經濟體系中，其資金來源為國內儲蓄與國外資金，且在利率水準r*國外資金可無 限供給（如圖所示）。若僅對國內儲蓄報酬課稅，則均衡時，下列敘述何者正確？ r*', '["國內儲蓄和國外資金流入皆增加", "國內儲蓄和國外資金流入皆減少", "國內儲蓄增加但國外資金流入減少", "國內儲蓄減少但國外資金流入增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00431', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '關於閉鎖效果（lock-ineffect）之敘述，下列何者正確？', '["對資本利得課稅產生的影響", "因為景氣好，資產持有者傾向繼續持有", "利率高時，投資者傾向繼續持有資產", "可抑制投機，提升資本市場效率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "41b2dab8a761", "answer_pdf_sha1": "b2eadbf1ac29", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
